            SendEntityNotification("Department", id.ToString(), departmentName, EntityOperation.DELETE);

            return RedirectToAction("Index");
        }

        protected override void Dispose(bool disposing)
        {
            if (disposing)
            {
                db.Dispose();
            }
            base.Dispose(disposing);
