using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests;

public static class TestHelper
{
    public static SchoolContext CreateContext(string? dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var options = new DbContextOptionsBuilder<SchoolContext>()
            .UseInMemoryDatabase(databaseName: dbName)
            .Options;
        return new SchoolContext(options);
    }

    public static SchoolContext CreateSeededContext(string? dbName = null)
    {
        dbName ??= Guid.NewGuid().ToString();
        var context = CreateContext(dbName);
        SeedData(context);
        return context;
    }

    public static void SeedData(SchoolContext context)
    {
        var dept = new Department
        {
            DepartmentID = 1,
            Name = "Engineering",
            Budget = 350000,
            StartDate = DateTime.Parse("2007-09-01")
        };
        context.Departments.Add(dept);

        var dept2 = new Department
        {
            DepartmentID = 2,
            Name = "Mathematics",
            Budget = 100000,
            StartDate = DateTime.Parse("2007-09-01")
        };
        context.Departments.Add(dept2);

        context.Courses.AddRange(
            new Course { CourseID = 1050, Title = "Chemistry", Credits = 3, DepartmentID = 1 },
            new Course { CourseID = 1045, Title = "Calculus", Credits = 4, DepartmentID = 2 },
            new Course { CourseID = 2021, Title = "Composition", Credits = 3, DepartmentID = 1 }
        );

        var student1 = new Student
        {
            ID = 1,
            FirstMidName = "Carson",
            LastName = "Alexander",
            EnrollmentDate = DateTime.Parse("2010-09-01")
        };
        var student2 = new Student
        {
            ID = 2,
            FirstMidName = "Meredith",
            LastName = "Alonso",
            EnrollmentDate = DateTime.Parse("2012-09-01")
        };
        var student3 = new Student
        {
            ID = 3,
            FirstMidName = "Arturo",
            LastName = "Anand",
            EnrollmentDate = DateTime.Parse("2013-09-01")
        };
        context.Students.AddRange(student1, student2, student3);

        var instructor1 = new Instructor
        {
            ID = 10,
            FirstMidName = "Kim",
            LastName = "Abercrombie",
            HireDate = DateTime.Parse("1995-03-11")
        };
        var instructor2 = new Instructor
        {
            ID = 11,
            FirstMidName = "Fadi",
            LastName = "Fakhouri",
            HireDate = DateTime.Parse("2002-07-06")
        };
        context.Instructors.AddRange(instructor1, instructor2);

        context.OfficeAssignments.Add(new OfficeAssignment
        {
            InstructorID = 11,
            Location = "Smith 17"
        });

        context.CourseAssignments.AddRange(
            new CourseAssignment { CourseID = 1050, InstructorID = 10 },
            new CourseAssignment { CourseID = 1045, InstructorID = 11 }
        );

        context.Enrollments.AddRange(
            new Enrollment { EnrollmentID = 1, StudentID = 1, CourseID = 1050, Grade = Grade.A },
            new Enrollment { EnrollmentID = 2, StudentID = 2, CourseID = 1045, Grade = Grade.B },
            new Enrollment { EnrollmentID = 3, StudentID = 3, CourseID = 1050 }
        );

        context.SaveChanges();
    }
}

using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models;

public class PersonTests
{
    private class ConcretePerson : Person { }

    [Fact]
    public void FullName_ReturnsLastNameCommaFirstName()
    {
        var person = new ConcretePerson { LastName = "Smith", FirstMidName = "John" };
        Assert.Equal("Smith, John", person.FullName);
    }

    [Fact]
    public void FullName_HandlesEmptyParts()
    {
        var person = new ConcretePerson { LastName = "", FirstMidName = "" };
        Assert.Equal(", ", person.FullName);
    }

    [Fact]
    public void ID_DefaultsToZero()
    {
        var person = new ConcretePerson();
        Assert.Equal(0, person.ID);
    }

    [Fact]
    public void ID_CanBeSet()
    {
        var person = new ConcretePerson { ID = 42 };
        Assert.Equal(42, person.ID);
    }
}

using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models;

public class StudentTests
{
    [Fact]
    public void Student_InheritsFromPerson()
    {
        var student = new Student();
        Assert.IsAssignableFrom<Person>(student);
    }

    [Fact]
    public void Student_HasEnrollmentDate()
    {
        var date = new DateTime(2023, 9, 1);
        var student = new Student { EnrollmentDate = date };
        Assert.Equal(date, student.EnrollmentDate);
    }

    [Fact]
    public void Student_FullName_WorksFromPerson()
    {
        var student = new Student { LastName = "Doe", FirstMidName = "Jane" };
        Assert.Equal("Doe, Jane", student.FullName);
    }

    [Fact]
    public void Student_Enrollments_CanBeInitialized()
    {
        var student = new Student { Enrollments = new List<Enrollment>() };
        Assert.NotNull(student.Enrollments);
        Assert.Empty(student.Enrollments);
    }
}

using ContosoUniversity.Models;

namespace ContosoUniversity.Tests.Models;

public class InstructorTests
{
    [Fact]
    public void Instructor_InheritsFromPerson()
    {
        var instructor = new Instructor();
        Assert.IsAssignableFrom<Person>(instructor);
    }

    [Fact]
    public void Instructor_HasHireDate()
    {
        var date = new DateTime(2000, 1, 15);
        var instructor = new Instructor { HireDate = date };
        Assert.Equal(date, instructor.HireDate);
    }

