using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

public class NotificationServiceTests : IDisposable
{
    private readonly NotificationService _service;

    public NotificationServiceTests()
    {
        _service = new NotificationService();
        // Drain any notifications left by other tests (shared static queue)
        while (_service.ReceiveNotification() != null) { }
    }

    public void Dispose()
    {
        _service.Dispose();
    }

    [Fact]
    public void SendNotification_WithDisplayName_EnqueuesNotification()
    {
        _service.SendNotification("Student", "1", "John Doe", EntityOperation.CREATE, "admin");

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("Student", notification.EntityType);
        Assert.Equal("1", notification.EntityId);
        Assert.Equal("CREATE", notification.Operation);
        Assert.Contains("John Doe", notification.Message);
        Assert.Contains("created", notification.Message);
        Assert.Equal("admin", notification.CreatedBy);
        Assert.False(notification.IsRead);
    }

    [Fact]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        _service.SendNotification("Course", "42", EntityOperation.UPDATE, "system");

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("ID: 42", notification.Message);
        Assert.Contains("updated", notification.Message);
    }

    [Fact]
    public void SendNotification_DefaultUser_IsSystem()
    {
        _service.SendNotification("Student", "1", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("System", notification.CreatedBy);
    }

    [Fact]
    public void SendNotification_Delete_GeneratesDeleteMessage()
    {
        _service.SendNotification("Department", "5", "Engineering", EntityOperation.DELETE, "admin");

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Equal("DELETE", notification.Operation);
        Assert.Contains("deleted", notification.Message);
        Assert.Contains("Engineering", notification.Message);
    }

    [Fact]
    public void SendNotification_Create_GeneratesCreateMessage()
    {
        _service.SendNotification("Course", "1", "Chemistry", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("New", notification.Message);
        Assert.Contains("created", notification.Message);
    }

    [Fact]
    public void SendNotification_Update_GeneratesUpdateMessage()
    {
        _service.SendNotification("Instructor", "3", "Dr. Smith", EntityOperation.UPDATE);

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("updated", notification.Message);
    }

    [Fact]
    public void ReceiveNotification_ReturnsNull_WhenQueueIsEmpty()
    {
        var notification = _service.ReceiveNotification();
        Assert.Null(notification);
    }

    [Fact]
    public void ReceiveNotification_ReturnsInFIFOOrder()
    {
        _service.SendNotification("A", "1", EntityOperation.CREATE);
        _service.SendNotification("B", "2", EntityOperation.UPDATE);
        _service.SendNotification("C", "3", EntityOperation.DELETE);

        var n1 = _service.ReceiveNotification();
        var n2 = _service.ReceiveNotification();
        var n3 = _service.ReceiveNotification();

        Assert.Equal("A", n1!.EntityType);
        Assert.Equal("B", n2!.EntityType);
        Assert.Equal("C", n3!.EntityType);
    }

    [Fact]
    public void ReceiveNotification_RemovesFromQueue()
    {
        _service.SendNotification("Test", "1", EntityOperation.CREATE);

        var first = _service.ReceiveNotification();
        Assert.NotNull(first);

        var second = _service.ReceiveNotification();
        Assert.Null(second);
    }

    [Fact]
    public void MarkAsRead_DoesNotThrow()
    {
        // MarkAsRead is a no-op for in-memory implementation
        var ex = Record.Exception(() => _service.MarkAsRead(1));
        Assert.Null(ex);
    }

    [Fact]
    public void MarkAsRead_WithAnyId_DoesNotThrow()
    {
        var ex = Record.Exception(() => _service.MarkAsRead(999));
        Assert.Null(ex);
    }

    [Fact]
    public void Dispose_DoesNotThrow()
    {
        var service = new NotificationService();
        var ex = Record.Exception(() => service.Dispose());
        Assert.Null(ex);
    }

    [Fact]
    public void SendNotification_SetsCreatedAt()
    {
        var before = DateTime.Now;
        _service.SendNotification("Test", "1", EntityOperation.CREATE);
        var after = DateTime.Now;

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.InRange(notification.CreatedAt, before, after);
    }

    [Fact]
    public void SendNotification_WithNullDisplayName_UsesIdFormat()
    {
        _service.SendNotification("Student", "7", null, EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("ID: 7", notification.Message);
    }

    [Fact]
    public void SendNotification_WithEmptyDisplayName_UsesIdFormat()
    {
        _service.SendNotification("Student", "7", "", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("ID: 7", notification.Message);
    }

    [Fact]
    public void SendNotification_WithWhitespaceDisplayName_UsesIdFormat()
    {
        _service.SendNotification("Student", "7", "   ", EntityOperation.CREATE);

        var notification = _service.ReceiveNotification();
        Assert.NotNull(notification);
        Assert.Contains("ID: 7", notification.Message);
    }

    [Fact]
    public void SendNotification_MultipleNotifications_AllQueued()
    {
        for (int i = 0; i < 5; i++)
        {
            _service.SendNotification("Test", i.ToString(), EntityOperation.CREATE);
        }

        for (int i = 0; i < 5; i++)
        {
            var n = _service.ReceiveNotification();
            Assert.NotNull(n);
            Assert.Equal(i.ToString(), n.EntityId);
        }

        Assert.Null(_service.ReceiveNotification());
    }
}

namespace ContosoUniversity.Tests;

public class PaginatedListTests
{
    [Fact]
    public void Constructor_SetsProperties()
    {
        var items = new List<string> { "a", "b", "c" };
        var list = new PaginatedList<string>(items, 10, 2, 3);

        Assert.Equal(2, list.PageIndex);
        Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
        Assert.Equal(3, list.Count);
        Assert.Contains("a", list);
        Assert.Contains("b", list);
        Assert.Contains("c", list);
    }

    [Fact]
    public void HasPreviousPage_ReturnsFalse_WhenOnFirstPage()
    {
        var list = new PaginatedList<string>(new List<string>(), 10, 1, 5);
        Assert.False(list.HasPreviousPage);
    }

    [Fact]
    public void HasPreviousPage_ReturnsTrue_WhenNotOnFirstPage()
    {
        var list = new PaginatedList<string>(new List<string>(), 10, 2, 5);
        Assert.True(list.HasPreviousPage);
    }

    [Fact]
    public void HasNextPage_ReturnsFalse_WhenOnLastPage()
    {
        var list = new PaginatedList<string>(new List<string>(), 10, 2, 5);
        Assert.False(list.HasNextPage); // TotalPages = 2, PageIndex = 2
    }

    [Fact]
    public void HasNextPage_ReturnsTrue_WhenNotOnLastPage()
    {
        var list = new PaginatedList<string>(new List<string>(), 10, 1, 5);
        Assert.True(list.HasNextPage); // TotalPages = 2, PageIndex = 1
    }

    [Fact]
    public void TotalPages_CalculatesCorrectly_ExactDivision()
    {
        var list = new PaginatedList<string>(new List<string>(), 10, 1, 5);
        Assert.Equal(2, list.TotalPages);
    }

    [Fact]
    public void TotalPages_CalculatesCorrectly_WithRemainder()
    {
        var list = new PaginatedList<string>(new List<string>(), 11, 1, 5);
        Assert.Equal(3, list.TotalPages); // ceil(11/5) = 3
    }

    [Fact]
    public void TotalPages_IsOne_WhenCountIsLessThanPageSize()
    {
        var list = new PaginatedList<string>(new List<string>(), 3, 1, 10);
        Assert.Equal(1, list.TotalPages);
    }

    [Fact]
    public void TotalPages_IsZero_WhenCountIsZero()
    {
        var list = new PaginatedList<string>(new List<string>(), 0, 1, 10);
        Assert.Equal(0, list.TotalPages);
    }

    [Fact]
    public void Create_ReturnsCorrectPage()
    {
        var source = Enumerable.Range(1, 30).AsQueryable();
        var result = PaginatedList<int>.Create(source, 2, 10);

        Assert.Equal(2, result.PageIndex);
        Assert.Equal(3, result.TotalPages);
        Assert.Equal(10, result.Count);
        Assert.Equal(11, result[0]); // Page 2 starts at item 11
        Assert.Equal(20, result[9]);
    }

    [Fact]
    public void Create_FirstPage_ReturnsFirstItems()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.Equal(1, result.PageIndex);
        Assert.Equal(10, result.Count);
        Assert.Equal(1, result[0]);
        Assert.Equal(10, result[9]);
        Assert.True(result.HasNextPage);
        Assert.False(result.HasPreviousPage);
    }

    [Fact]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();
        var result = PaginatedList<int>.Create(source, 3, 10);

        Assert.Equal(3, result.PageIndex);
        Assert.Equal(5, result.Count);
        Assert.Equal(21, result[0]);
        Assert.Equal(25, result[4]);
        Assert.False(result.HasNextPage);
        Assert.True(result.HasPreviousPage);
    }

    [Fact]
    public void Create_SinglePage_NoPagination()
    {
        var source = Enumerable.Range(1, 5).AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.Equal(1, result.PageIndex);
        Assert.Equal(1, result.TotalPages);
        Assert.Equal(5, result.Count);
        Assert.False(result.HasNextPage);
        Assert.False(result.HasPreviousPage);
    }

    [Fact]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var source = Enumerable.Empty<int>().AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.Empty(result);
        Assert.Equal(0, result.TotalPages);
        Assert.False(result.HasNextPage);
        Assert.False(result.HasPreviousPage);
    }
}

