namespace ContosoUniversity.Tests;

public class PaginatedListTests
{
    [Fact]
    public void Constructor_SetsProperties()
    {
        var items = new List<string> { "a", "b", "c" };
        var list = new PaginatedList<string>(items, 10, 2, 3);

        Assert.Equal(2, list.PageIndex);
        Assert.Equal(4, list.TotalPages); // ceil(10/3) = 4
        Assert.Equal(3, list.Count);
        Assert.Contains("a", list);
        Assert.Contains("b", list);
        Assert.Contains("c", list);
    }

    [Fact]
    public void HasPreviousPage_ReturnsFalse_WhenOnFirstPage()
    {
        var list = new PaginatedList<string>(new List<string>(), 10, 1, 5);
        Assert.False(list.HasPreviousPage);
    }

    [Fact]
    public void HasPreviousPage_ReturnsTrue_WhenNotOnFirstPage()
    {
        var list = new PaginatedList<string>(new List<string>(), 10, 2, 5);
        Assert.True(list.HasPreviousPage);
    }

    [Fact]
    public void HasNextPage_ReturnsFalse_WhenOnLastPage()
    {
        var list = new PaginatedList<string>(new List<string>(), 10, 2, 5);
        Assert.False(list.HasNextPage); // TotalPages = 2, PageIndex = 2
    }

    [Fact]
    public void HasNextPage_ReturnsTrue_WhenNotOnLastPage()
    {
        var list = new PaginatedList<string>(new List<string>(), 10, 1, 5);
        Assert.True(list.HasNextPage); // TotalPages = 2, PageIndex = 1
    }

    [Fact]
    public void TotalPages_CalculatesCorrectly_ExactDivision()
    {
        var list = new PaginatedList<string>(new List<string>(), 10, 1, 5);
        Assert.Equal(2, list.TotalPages);
    }

    [Fact]
    public void TotalPages_CalculatesCorrectly_WithRemainder()
    {
        var list = new PaginatedList<string>(new List<string>(), 11, 1, 5);
        Assert.Equal(3, list.TotalPages); // ceil(11/5) = 3
    }

    [Fact]
    public void TotalPages_IsOne_WhenCountIsLessThanPageSize()
    {
        var list = new PaginatedList<string>(new List<string>(), 3, 1, 10);
        Assert.Equal(1, list.TotalPages);
    }

    [Fact]
    public void TotalPages_IsZero_WhenCountIsZero()
    {
        var list = new PaginatedList<string>(new List<string>(), 0, 1, 10);
        Assert.Equal(0, list.TotalPages);
    }

    [Fact]
    public void Create_ReturnsCorrectPage()
    {
        var source = Enumerable.Range(1, 30).AsQueryable();
        var result = PaginatedList<int>.Create(source, 2, 10);

        Assert.Equal(2, result.PageIndex);
        Assert.Equal(3, result.TotalPages);
        Assert.Equal(10, result.Count);
        Assert.Equal(11, result[0]); // Page 2 starts at item 11
        Assert.Equal(20, result[9]);
    }

    [Fact]
    public void Create_FirstPage_ReturnsFirstItems()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.Equal(1, result.PageIndex);
        Assert.Equal(10, result.Count);
        Assert.Equal(1, result[0]);
        Assert.Equal(10, result[9]);
        Assert.True(result.HasNextPage);
        Assert.False(result.HasPreviousPage);
    }

    [Fact]
    public void Create_LastPage_ReturnsRemainingItems()
    {
        var source = Enumerable.Range(1, 25).AsQueryable();
        var result = PaginatedList<int>.Create(source, 3, 10);

        Assert.Equal(3, result.PageIndex);
        Assert.Equal(5, result.Count);
        Assert.Equal(21, result[0]);
        Assert.Equal(25, result[4]);
        Assert.False(result.HasNextPage);
        Assert.True(result.HasPreviousPage);
    }

    [Fact]
    public void Create_SinglePage_NoPagination()
    {
        var source = Enumerable.Range(1, 5).AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.Equal(1, result.PageIndex);
        Assert.Equal(1, result.TotalPages);
        Assert.Equal(5, result.Count);
        Assert.False(result.HasNextPage);
        Assert.False(result.HasPreviousPage);
    }

    [Fact]
    public void Create_EmptySource_ReturnsEmptyList()
    {
        var source = Enumerable.Empty<int>().AsQueryable();
        var result = PaginatedList<int>.Create(source, 1, 10);

        Assert.Empty(result);
        Assert.Equal(0, result.TotalPages);
        Assert.False(result.HasNextPage);
        Assert.False(result.HasPreviousPage);
    }
}

