using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

public class StudentsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly StudentsController _controller;

    public StudentsControllerTests()
    {
        _context = TestHelper.CreateSeededContext();
        _controller = new StudentsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    // --- Index Tests ---

    [Fact]
    public void Index_ReturnsViewWithPaginatedStudents()
    {
        var result = _controller.Index(null, null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.NotEmpty(model);
    }

    [Fact]
    public void Index_DefaultSort_OrdersByLastNameAsc()
    {
        var result = _controller.Index(null, null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);

        var names = model.Select(s => s.LastName).ToList();
        Assert.Equal(names.OrderBy(n => n), names);
    }

    [Fact]
    public void Index_NameDescSort_OrdersByLastNameDesc()
    {
        var result = _controller.Index("name_desc", null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);

        var names = model.Select(s => s.LastName).ToList();
        Assert.Equal(names.OrderByDescending(n => n), names);
    }

    [Fact]
    public void Index_DateSort_OrdersByEnrollmentDateAsc()
    {
        var result = _controller.Index("Date", null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);

        var dates = model.Select(s => s.EnrollmentDate).ToList();
        Assert.Equal(dates.OrderBy(d => d), dates);
    }

    [Fact]
    public void Index_DateDescSort_OrdersByEnrollmentDateDesc()
    {
        var result = _controller.Index("date_desc", null, null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);

        var dates = model.Select(s => s.EnrollmentDate).ToList();
        Assert.Equal(dates.OrderByDescending(d => d), dates);
    }

    [Fact]
    public void Index_SearchByLastName_FiltersResults()
    {
        var result = _controller.Index(null, null, "Alexander", null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);

        Assert.Single(model);
        Assert.Equal("Alexander", model[0].LastName);
    }

    [Fact]
    public void Index_SearchByFirstName_FiltersResults()
    {
        var result = _controller.Index(null, null, "Carson", null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);

        Assert.Single(model);
        Assert.Equal("Carson", model[0].FirstMidName);
    }

    [Fact]
    public void Index_SearchNoMatch_ReturnsEmpty()
    {
        var result = _controller.Index(null, null, "NonExistent", null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Empty(model);
    }

    [Fact]
    public void Index_SearchString_ResetsPageToOne()
    {
        var result = _controller.Index(null, null, "Alexander", 5);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Equal(1, model.PageIndex);
    }

    [Fact]
    public void Index_NullSearchString_UsesCurrentFilter()
    {
        var result = _controller.Index(null, "Alexander", null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<PaginatedList<Student>>(viewResult.Model);
        Assert.Single(model);
    }

    [Fact]
    public void Index_SetsViewBagProperties()
    {
        _controller.Index("Date", null, "test", null);

        Assert.Equal("Date", _controller.ViewBag.CurrentSort);
        Assert.Equal("date_desc", _controller.ViewBag.DateSortParm);
        Assert.Equal("", _controller.ViewBag.NameSortParm);
        Assert.Equal("test", _controller.ViewBag.CurrentFilter);
    }

    [Fact]
    public void Index_DefaultSortOrder_SetsCorrectSortParms()
    {
        _controller.Index(null, null, null, null);

        Assert.Null(_controller.ViewBag.CurrentSort);
        Assert.Equal("name_desc", _controller.ViewBag.NameSortParm);
        Assert.Equal("Date", _controller.ViewBag.DateSortParm);
    }

    // --- Details Tests ---

    [Fact]
    public void Details_WithValidId_ReturnsView()
    {
        var result = _controller.Details(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal("Alexander", model.LastName);
    }

    [Fact]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_IncludesEnrollments()
    {
        var result = _controller.Details(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.NotNull(model.Enrollments);
        Assert.NotEmpty(model.Enrollments);
    }

    // --- Create GET Tests ---

    [Fact]
    public void Create_GET_ReturnsViewWithDefaultDate()
    {
        var result = _controller.Create();

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal(DateTime.Today, model.EnrollmentDate);
    }

    // --- Create POST Tests ---

    [Fact]
    public void Create_POST_ValidStudent_RedirectsToIndex()
    {
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        var result = _controller.Create(student);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Create_POST_ValidStudent_SavesInDatabase()
    {
        var student = new Student
        {
            FirstMidName = "New",
            LastName = "Person",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        _controller.Create(student);

        var saved = _context.Students.FirstOrDefault(s => s.LastName == "Person");
        Assert.NotNull(saved);
        Assert.Equal("New", saved.FirstMidName);
    }

    [Fact]
    public void Create_POST_MinValueDate_AddsModelError()
    {
        var student = new Student
        {
            FirstMidName = "Bad",
            LastName = "Date",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Create(student);

        Assert.IsType<ViewResult>(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Create_POST_DateBelow1753_AddsModelError()
    {
        var student = new Student
        {
            FirstMidName = "Old",
            LastName = "Date",
            EnrollmentDate = new DateTime(1752, 12, 31)
        };

        var result = _controller.Create(student);

        Assert.IsType<ViewResult>(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
    public void Create_POST_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            FirstMidName = "Test",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        var result = _controller.Create(student);

        Assert.IsType<ViewResult>(result);
    }

    // --- Edit GET Tests ---

    [Fact]
    public void Edit_GET_WithValidId_ReturnsView()
    {
        var result = _controller.Edit(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Student>(viewResult.Model);
        Assert.Equal("Alexander", model.LastName);
    }

    [Fact]
    public void Edit_GET_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_GET_WithInvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(999);
        Assert.IsType<NotFoundResult>(result);
    }

    // --- Edit POST Tests ---

    [Fact]
    public void Edit_POST_ValidStudent_RedirectsToIndex()
    {
        var student = new Student
        {
            ID = 1,
            FirstMidName = "Updated",
            LastName = "Name",
            EnrollmentDate = new DateTime(2023, 9, 1)
        };

        // Detach existing entity to avoid tracking conflict
        var existingEntry = _context.ChangeTracker.Entries<Student>().FirstOrDefault(e => ((Student)e.Entity).ID == 1);
        existingEntry?.State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var result = _controller.Edit(student);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Edit_POST_MinValueDate_ReturnsView()
    {
        var student = new Student
        {
            ID = 1,
            FirstMidName = "Carson",
            LastName = "Alexander",
            EnrollmentDate = DateTime.MinValue
        };

        var result = _controller.Edit(student);

        Assert.IsType<ViewResult>(result);
        Assert.False(_controller.ModelState.IsValid);
    }

    [Fact]
