using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.AspNetCore.Hosting;
using Microsoft.AspNetCore.Http;
using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.Logging;
using Moq;

namespace ContosoUniversity.Tests.Controllers;

public class CoursesControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly CoursesController _controller;
    private readonly Mock<IWebHostEnvironment> _envMock;
    private readonly Mock<ILogger<CoursesController>> _loggerMock;

    public CoursesControllerTests()
    {
        _context = TestHelper.CreateSeededContext();
        _envMock = new Mock<IWebHostEnvironment>();
        _envMock.Setup(e => e.WebRootPath).Returns(Path.GetTempPath());
        _envMock.Setup(e => e.ContentRootPath).Returns(Path.GetTempPath());
        _loggerMock = new Mock<ILogger<CoursesController>>();
        _controller = new CoursesController(_context, _envMock.Object, _loggerMock.Object);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    // --- Index ---

    [Fact]
    public void Index_ReturnsViewWithCourses()
    {
        var result = _controller.Index();

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<List<Course>>(viewResult.Model);
        Assert.Equal(3, model.Count);
    }

    // --- Details ---

    [Fact]
    public void Details_WithValidId_ReturnsView()
    {
        var result = _controller.Details(1050);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Course>(viewResult.Model);
        Assert.Equal("Chemistry", model.Title);
    }

    [Fact]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_IncludesDepartment()
    {
        var result = _controller.Details(1050);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Course>(viewResult.Model);
        Assert.NotNull(model.Department);
        Assert.Equal("Engineering", model.Department.Name);
    }

    // --- Create GET ---

    [Fact]
    public void Create_GET_ReturnsViewWithDepartmentSelectList()
    {
        var result = _controller.Create();

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.NotNull(_controller.ViewBag.DepartmentID);
        var model = Assert.IsType<Course>(viewResult.Model);
    }

    // --- Create POST ---

    [Fact]
    public void Create_POST_ValidCourse_RedirectsToIndex()
    {
        var course = new Course
        {
            CourseID = 9999,
            Title = "New Course",
            Credits = 3,
            DepartmentID = 1
        };

        var result = _controller.Create(course, null!);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Create_POST_ValidCourse_SavesInDatabase()
    {
        var course = new Course
        {
            CourseID = 8888,
            Title = "Saved Course",
            Credits = 4,
            DepartmentID = 1
        };

        _controller.Create(course, null!);

        var saved = _context.Courses.Find(8888);
        Assert.NotNull(saved);
        Assert.Equal("Saved Course", saved.Title);
    }

    [Fact]
    public void Create_POST_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 7777, DepartmentID = 1 };

        var result = _controller.Create(course, null!);

        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void Create_POST_WithInvalidImageExtension_ReturnsViewWithError()
    {
        var course = new Course { CourseID = 6666, Title = "Test", Credits = 3, DepartmentID = 1 };
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("test.exe");
        fileMock.Setup(f => f.Length).Returns(1024);

        var result = _controller.Create(course, fileMock.Object);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Create_POST_WithTooLargeFile_ReturnsViewWithError()
    {
        var course = new Course { CourseID = 5555, Title = "Test", Credits = 3, DepartmentID = 1 };
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("test.jpg");
        fileMock.Setup(f => f.Length).Returns(6 * 1024 * 1024); // 6MB

        var result = _controller.Create(course, fileMock.Object);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Create_POST_WithValidImage_SavesFileAndCourse()
    {
        var course = new Course { CourseID = 4444, Title = "Image Test", Credits = 3, DepartmentID = 1 };
        var content = new byte[] { 1, 2, 3 };
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("material.png");
        fileMock.Setup(f => f.Length).Returns(content.Length);
        fileMock.Setup(f => f.CopyTo(It.IsAny<Stream>()));

        var result = _controller.Create(course, fileMock.Object);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        var saved = _context.Courses.Find(4444);
        Assert.NotNull(saved);
        Assert.StartsWith("/Uploads/TeachingMaterials/", saved.TeachingMaterialImagePath);
    }

    // --- Edit GET ---

    [Fact]
    public void Edit_GET_WithValidId_ReturnsView()
    {
        var result = _controller.Edit(1050);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Course>(viewResult.Model);
        Assert.Equal("Chemistry", model.Title);
    }

    [Fact]
    public void Edit_GET_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_GET_WithInvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(9999);
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_GET_SetsViewBagDepartment()
    {
        _controller.Edit(1050);
        Assert.NotNull(_controller.ViewBag.DepartmentID);
    }

    // --- Edit POST ---

    [Fact]
    public void Edit_POST_ValidCourse_RedirectsToIndex()
    {
        // Detach tracked entity
        var tracked = _context.ChangeTracker.Entries<Course>().FirstOrDefault(e => ((Course)e.Entity).CourseID == 1050);
        tracked?.State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var course = new Course
        {
            CourseID = 1050,
            Title = "Updated Chemistry",
            Credits = 4,
            DepartmentID = 1
        };

        var result = _controller.Edit(course, null!);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Edit_POST_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Title", "Required");
        var course = new Course { CourseID = 1050, DepartmentID = 1 };

        var result = _controller.Edit(course, null!);

        Assert.IsType<ViewResult>(result);
    }

    [Fact]
    public void Edit_POST_WithInvalidImage_ReturnsViewWithError()
    {
        var course = new Course { CourseID = 1050, Title = "Test", Credits = 3, DepartmentID = 1 };
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("bad.txt");
        fileMock.Setup(f => f.Length).Returns(100);

        var result = _controller.Edit(course, fileMock.Object);

        var viewResult = Assert.IsType<ViewResult>(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    [Fact]
    public void Edit_POST_WithOversizedImage_ReturnsViewWithError()
    {
        var course = new Course { CourseID = 1050, Title = "Test", Credits = 3, DepartmentID = 1 };
        var fileMock = new Mock<IFormFile>();
        fileMock.Setup(f => f.FileName).Returns("big.jpg");
        fileMock.Setup(f => f.Length).Returns(10 * 1024 * 1024);

        var result = _controller.Edit(course, fileMock.Object);

        Assert.IsType<ViewResult>(result);
        Assert.True(_controller.ModelState.ContainsKey("teachingMaterialImage"));
    }

    // --- Delete GET ---

    [Fact]
    public void Delete_GET_WithValidId_ReturnsView()
    {
        var result = _controller.Delete(1050);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Course>(viewResult.Model);
        Assert.Equal("Chemistry", model.Title);
    }

    [Fact]
    public void Delete_GET_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    // --- DeleteConfirmed ---

    [Fact]
    public void DeleteConfirmed_RemovesCourseAndRedirects()
    {
        var result = _controller.DeleteConfirmed(1050);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        Assert.Null(_context.Courses.Find(1050));
    }

    [Fact]
    public void DeleteConfirmed_WithImagePath_DeletesFileAndCourse()
    {
        // Add a course with an image path
        var course = _context.Courses.Find(1045)!;
        course.TeachingMaterialImagePath = "/Uploads/TeachingMaterials/nonexistent.jpg";
        _context.SaveChanges();

        var result = _controller.DeleteConfirmed(1045);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        Assert.Null(_context.Courses.Find(1045));
    }
}

