    [Fact]
    public void Index_ReturnsViewWithDepartments()
    {
        var result = _controller.Index();

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsAssignableFrom<List<Department>>(viewResult.Model);
        Assert.Equal(2, model.Count);
    }

    // --- Details ---

    [Fact]
    public void Details_WithValidId_ReturnsView()
    {
        var result = _controller.Details(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Department>(viewResult.Model);
        Assert.Equal("Engineering", model.Name);
    }

    [Fact]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_WithInvalidId_ReturnsNotFound()
    {
        var result = _controller.Details(999);
        Assert.IsType<NotFoundResult>(result);
    }

    // --- Create GET ---

    [Fact]
    public void Create_GET_ReturnsViewWithInstructorSelectList()
    {
        var result = _controller.Create();

        Assert.IsType<ViewResult>(result);
        Assert.NotNull(_controller.ViewBag.InstructorID);
    }

    // --- Create POST ---

    [Fact]
    public void Create_POST_ValidDepartment_RedirectsToIndex()
    {
        var department = new Department
        {
            Name = "Physics",
            Budget = 200000,
            StartDate = new DateTime(2023, 1, 1)
        };

        var result = _controller.Create(department);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Create_POST_ValidDepartment_SavesInDatabase()
    {
        var department = new Department
        {
            Name = "Biology",
            Budget = 150000,
            StartDate = new DateTime(2023, 1, 1)
        };

        _controller.Create(department);

        var saved = _context.Departments.FirstOrDefault(d => d.Name == "Biology");
        Assert.NotNull(saved);
        Assert.Equal(150000, saved.Budget);
    }

    [Fact]
    public void Create_POST_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Name", "Required");
        var department = new Department();

        var result = _controller.Create(department);

        Assert.IsType<ViewResult>(result);
    }

    // --- Edit GET ---

    [Fact]
    public void Edit_GET_WithValidId_ReturnsView()
    {
        var result = _controller.Edit(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Department>(viewResult.Model);
        Assert.Equal("Engineering", model.Name);
    }

    [Fact]
    public void Edit_GET_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Edit(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Edit_GET_WithInvalidId_ReturnsNotFound()
    {
        var result = _controller.Edit(999);
        Assert.IsType<NotFoundResult>(result);
    }

    [Fact]
    public void Edit_GET_SetsViewBagInstructorID()
    {
        _controller.Edit(1);
        Assert.NotNull(_controller.ViewBag.InstructorID);
    }

    // --- Edit POST ---

    [Fact]
    public void Edit_POST_ValidDepartment_RedirectsToIndex()
    {
        var tracked = _context.ChangeTracker.Entries<Department>()
            .FirstOrDefault(e => ((Department)e.Entity).DepartmentID == 1);
        tracked?.State = Microsoft.EntityFrameworkCore.EntityState.Detached;

        var department = new Department
        {
            DepartmentID = 1,
            Name = "Updated Engineering",
            Budget = 400000,
            StartDate = new DateTime(2007, 9, 1)
        };

        var result = _controller.Edit(department);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Edit_POST_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("Name", "Required");
        var department = new Department { DepartmentID = 1 };

        var result = _controller.Edit(department);

        Assert.IsType<ViewResult>(result);
    }

    // --- Delete GET ---

    [Fact]
    public void Delete_GET_WithValidId_ReturnsView()
    {
        var result = _controller.Delete(1);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Department>(viewResult.Model);
        Assert.Equal("Engineering", model.Name);
    }

    [Fact]
    public void Delete_GET_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_GET_WithInvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(999);
        Assert.IsType<NotFoundResult>(result);
    }

    // --- DeleteConfirmed ---

    [Fact]
    public void DeleteConfirmed_RemovesDepartmentAndRedirects()
    {
        var result = _controller.DeleteConfirmed(2);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);

        var deleted = _context.Departments.Find(2);
        Assert.Null(deleted);
    }
}

