using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Models.SchoolViewModels;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

public class InstructorsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly InstructorsController _controller;

    public InstructorsControllerTests()
    {
        _context = TestHelper.CreateSeededContext();
        _controller = new InstructorsController(_context);
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    // --- Index ---

    [Fact]
    public void Index_ReturnsViewWithInstructorIndexData()
    {
        var result = _controller.Index(null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
        Assert.NotNull(model.Instructors);
        Assert.Equal(2, model.Instructors.Count());
    }

    [Fact]
    public void Index_WithInstructorId_SetsCourses()
    {
        var result = _controller.Index(10, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
        Assert.NotNull(model.Courses);
        Assert.Single(model.Courses); // Instructor 10 has 1 course assignment
        Assert.Equal(10, _controller.ViewBag.InstructorID);
    }

    [Fact]
    public void Index_WithInstructorIdAndCourseId_SetsEnrollments()
    {
        var result = _controller.Index(10, 1050);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
        Assert.NotNull(model.Enrollments);
        Assert.Equal(1050, _controller.ViewBag.CourseID);
    }

    [Fact]
    public void Index_OrdersInstructorsByLastName()
    {
        var result = _controller.Index(null, null);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<InstructorIndexData>(viewResult.Model);
        var names = model.Instructors.Select(i => i.LastName).ToList();
        Assert.Equal(names.OrderBy(n => n), names);
    }

    // --- Details ---

    [Fact]
    public void Details_WithValidId_ReturnsView()
    {
        var result = _controller.Details(10);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Instructor>(viewResult.Model);
        Assert.Equal("Abercrombie", model.LastName);
    }

    [Fact]
    public void Details_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Details(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Details_WithInvalidId_ReturnsNotFound()
    {
        var result = _controller.Details(999);
        Assert.IsType<NotFoundResult>(result);
    }

    // --- Create GET ---

    [Fact]
    public void Create_GET_ReturnsViewWithInstructorAndCourses()
    {
        var result = _controller.Create();

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Instructor>(viewResult.Model);
        Assert.NotNull(model.CourseAssignments);
        Assert.Empty(model.CourseAssignments);
        Assert.NotNull(_controller.ViewBag.Courses);
    }

    // --- Create POST ---

    [Fact]
    public void Create_POST_ValidInstructor_RedirectsToIndex()
    {
        var instructor = new Instructor
        {
            FirstMidName = "New",
            LastName = "Teacher",
            HireDate = new DateTime(2023, 1, 1)
        };

        var result = _controller.Create(instructor, null!);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
    }

    [Fact]
    public void Create_POST_ValidInstructor_SavesInDatabase()
    {
        var instructor = new Instructor
        {
            FirstMidName = "Saved",
            LastName = "Instructor",
            HireDate = new DateTime(2023, 1, 1)
        };

        _controller.Create(instructor, null!);

        var saved = _context.Instructors.FirstOrDefault(i => i.LastName == "Instructor");
        Assert.NotNull(saved);
        Assert.Equal("Saved", saved.FirstMidName);
    }

    [Fact]
    public void Create_POST_WithSelectedCourses_CreatesCourseAssignments()
    {
        var instructor = new Instructor
        {
            FirstMidName = "Course",
            LastName = "Assigner",
            HireDate = new DateTime(2023, 1, 1)
        };

        _controller.Create(instructor, new[] { "1050", "1045" });

        var saved = _context.Instructors.FirstOrDefault(i => i.LastName == "Assigner");
        Assert.NotNull(saved);
        Assert.Equal(2, saved.CourseAssignments.Count);
    }

    [Fact]
    public void Create_POST_InvalidModelState_ReturnsView()
    {
        _controller.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor { HireDate = new DateTime(2023, 1, 1) };

        var result = _controller.Create(instructor, null!);

        Assert.IsType<ViewResult>(result);
    }

    // --- Delete GET ---

    [Fact]
    public void Delete_GET_WithValidId_ReturnsView()
    {
        var result = _controller.Delete(10);

        var viewResult = Assert.IsType<ViewResult>(result);
        var model = Assert.IsType<Instructor>(viewResult.Model);
        Assert.Equal("Abercrombie", model.LastName);
    }

    [Fact]
    public void Delete_GET_WithNullId_ReturnsBadRequest()
    {
        var result = _controller.Delete(null);
        var statusResult = Assert.IsType<StatusCodeResult>(result);
        Assert.Equal(400, statusResult.StatusCode);
    }

    [Fact]
    public void Delete_GET_WithInvalidId_ReturnsNotFound()
    {
        var result = _controller.Delete(999);
        Assert.IsType<NotFoundResult>(result);
    }

    // --- DeleteConfirmed ---

    [Fact]
    public void DeleteConfirmed_RemovesInstructorAndRedirects()
    {
        var result = _controller.DeleteConfirmed(10);

        var redirectResult = Assert.IsType<RedirectToActionResult>(result);
        Assert.Equal("Index", redirectResult.ActionName);
        Assert.Null(_context.Instructors.Find(10));
    }

    [Fact]
    public void DeleteConfirmed_ClearsDepartmentAdministrator()
    {
        // Set instructor 10 as department administrator
        var dept = _context.Departments.Find(1)!;
        dept.InstructorID = 10;
        _context.SaveChanges();

        _controller.DeleteConfirmed(10);

        var updatedDept = _context.Departments.Find(1);
        Assert.Null(updatedDept!.InstructorID);
    }
}

