using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Services;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

public class NotificationsControllerTests : IDisposable
{
    private readonly SchoolContext _context;
    private readonly NotificationsController _controller;

    public NotificationsControllerTests()
    {
        _context = TestHelper.CreateContext();
        _controller = new NotificationsController(_context);

        // Drain any leftover notifications
        var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
        svc.Dispose();
    }

    public void Dispose()
    {
        _controller.Dispose();
        _context.Dispose();
    }

    [Fact]
    public void GetNotifications_ReturnsJsonResult()
    {
        var result = _controller.GetNotifications();
        Assert.IsType<JsonResult>(result);
    }

    [Fact]
    public void GetNotifications_ReturnsEmptyList_WhenNoNotifications()
    {
        var result = _controller.GetNotifications();

        Assert.IsType<JsonResult>(result);
        // The result contains an anonymous type with success, notifications, count
        var value = result.Value;
        Assert.NotNull(value);
    }

    [Fact]
    public void GetNotifications_ReturnsNotifications_WhenAvailable()
    {
        // Queue some notifications directly
        var service = new NotificationService();
        service.SendNotification("Student", "1", "Test", EntityOperation.CREATE);
        service.SendNotification("Course", "2", "Math", EntityOperation.UPDATE);

        var result = _controller.GetNotifications();

        Assert.IsType<JsonResult>(result);
        var value = result.Value;
        Assert.NotNull(value);
        service.Dispose();
    }

    [Fact]
    public void MarkAsRead_ReturnsJsonSuccess()
    {
        var result = _controller.MarkAsRead(1);

        Assert.IsType<JsonResult>(result);
        var value = result.Value;
        Assert.NotNull(value);
    }

    [Fact]
    public void Index_ReturnsViewResult()
    {
        var result = _controller.Index();
        Assert.IsType<ViewResult>(result);
    }
}

