using ContosoUniversity.Data;
using ContosoUniversity.Models;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests;

public class SchoolContextTests
{
    [Fact]
    public void SchoolContext_CanBeCreated()
    {
        using var context = TestHelper.CreateContext();
        Assert.NotNull(context);
    }

    [Fact]
    public void SchoolContext_HasAllDbSets()
    {
        using var context = TestHelper.CreateContext();
        Assert.NotNull(context.Courses);
        Assert.NotNull(context.Enrollments);
        Assert.NotNull(context.Departments);
        Assert.NotNull(context.OfficeAssignments);
        Assert.NotNull(context.CourseAssignments);
        Assert.NotNull(context.People);
        Assert.NotNull(context.Students);
        Assert.NotNull(context.Instructors);
        Assert.NotNull(context.Notifications);
    }

    [Fact]
    public void SchoolContext_CanAddAndRetrieveStudent()
    {
        using var context = TestHelper.CreateContext();
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.Parse("2023-09-01")
        };

        context.Students.Add(student);
        context.SaveChanges();

        var retrieved = context.Students.First();
        Assert.Equal("Test", retrieved.FirstMidName);
        Assert.Equal("Student", retrieved.LastName);
    }

    [Fact]
    public void SchoolContext_CanAddAndRetrieveInstructor()
    {
        using var context = TestHelper.CreateContext();
        var instructor = new Instructor
        {
            FirstMidName = "Dr",
            LastName = "Teacher",
            HireDate = DateTime.Parse("2020-01-15")
        };

        context.Instructors.Add(instructor);
        context.SaveChanges();

        var retrieved = context.Instructors.First();
        Assert.Equal("Dr", retrieved.FirstMidName);
    }

    [Fact]
    public void SchoolContext_CourseAssignment_HasCompositeKey()
    {
        using var context = TestHelper.CreateContext();

        var instructor = new Instructor
        {
            ID = 100,
            FirstMidName = "Test",
            LastName = "Instructor",
            HireDate = DateTime.Now
        };
        context.Instructors.Add(instructor);

        var dept = new Department
        {
            DepartmentID = 100,
            Name = "TestDept",
            Budget = 1000,
            StartDate = DateTime.Now
        };
        context.Departments.Add(dept);

        var course = new Course
        {
            CourseID = 100,
            Title = "Test",
            Credits = 3,
            DepartmentID = 100
        };
        context.Courses.Add(course);
        context.SaveChanges();

        var ca = new CourseAssignment { CourseID = 100, InstructorID = 100 };
        context.CourseAssignments.Add(ca);
        context.SaveChanges();

        var found = context.CourseAssignments.Find(100, 100);
        Assert.NotNull(found);
    }

    [Fact]
    public void SchoolContext_CanAddDepartment()
    {
        using var context = TestHelper.CreateContext();
        var dept = new Department
        {
            Name = "Science",
            Budget = 50000,
            StartDate = DateTime.Parse("2023-01-01")
        };

        context.Departments.Add(dept);
        context.SaveChanges();

        Assert.Equal(1, context.Departments.Count());
    }

    [Fact]
    public void SchoolContext_CanAddNotification()
    {
        using var context = TestHelper.CreateContext();
        var notification = new Notification
        {
            EntityType = "Student",
            EntityId = "1",
            Operation = "CREATE",
            Message = "Test notification",
            CreatedAt = DateTime.Now,
            CreatedBy = "system",
            IsRead = false
        };

        context.Notifications.Add(notification);
        context.SaveChanges();

        Assert.Equal(1, context.Notifications.Count());
    }

    [Fact]
    public void SchoolContext_TPH_Discriminator_Works()
    {
        using var context = TestHelper.CreateContext();

        context.Students.Add(new Student
        {
            FirstMidName = "S",
            LastName = "Student",
            EnrollmentDate = DateTime.Now
        });
        context.Instructors.Add(new Instructor
        {
            FirstMidName = "I",
            LastName = "Instructor",
            HireDate = DateTime.Now
        });
        context.SaveChanges();

        Assert.Equal(1, context.Students.Count());
        Assert.Equal(1, context.Instructors.Count());
        Assert.Equal(2, context.People.Count());
    }

    [Fact]
    public void SchoolContext_Seeded_HasExpectedData()
    {
        using var context = TestHelper.CreateSeededContext();

        Assert.Equal(3, context.Students.Count());
        Assert.Equal(2, context.Instructors.Count());
        Assert.Equal(2, context.Departments.Count());
        Assert.Equal(3, context.Courses.Count());
        Assert.Equal(3, context.Enrollments.Count());
        Assert.Equal(2, context.CourseAssignments.Count());
        Assert.Equal(1, context.OfficeAssignments.Count());
    }
}

